import android.app.Activity
import android.content.Context
import androidx.appcompat.app.AppCompatActivity
import com.android.billingclient.api.*
import java.security.MessageDigest
import java.security.NoSuchAlgorithmException

class PaymentProcessor(private val context: Context, private val listener: PaymentListener) {

    private lateinit var billingClient: BillingClient
    private var skuDetailsMap = mutableMapOf<String, SkuDetails>()

    fun init() {
        billingClient = BillingClient.newBuilder(context).setListener { result, purchases ->
            for (purchase in purchases!!) {
                when (result.responseCode) {
                    BillingClient.BillingResponseCode.OK -> handlePurchases(purchase)
                    else -> listener.onPurchaseError(result.responseCode)
                }
            }
        }.enablePendingPurchases().build()

        billingClient.startConnection(object : BillingClientStateListener {
            override fun onBillingSetupFinished(billingResult: BillingClient.BillingResponseCode) {
                if (billingResult == BillingClient.BillingResponseCode.OK) {
                    querySkuDetails()
                } else {
                    listener.onBillingSetupFailed(billingResult)
                }
            }

            override fun onBillingServiceDisconnected() {}
        })
    }

    private fun querySkuDetails() {
        val skuList = listOf("inapp:product1", "inapp:product2")
        val skuDetailsParams = SkuDetailsParams.newBuilder()
            .setSkusList(skuList)
            .setType(BillingClient.SkuType.INAPP)
            .build()

        billingClient.querySkuDetailsAsync(skuDetailsParams) { result, skuDetails ->
            if (result.responseCode == BillingClient.BillingResponseCode.OK && skuDetails != null) {
                for (skuDetail in skuDetails) {
                    skuDetailsMap[skuDetail.sku] = skuDetail
                }
                listener.onSkuDetailsLoaded(skuDetails)
            } else {
                listener.onQuerySkuDetailsFailed(result.responseCode)
            }
        }
    }

    fun launchPurchaseFlow(activity: Activity, sku: String) {
        val params = BillingFlowParams.newBuilder()
            .setSkuDetails(skuDetailsMap[sku]!!)
            .build()

        billingClient.launchBillingFlow(activity, params).apply {
            addOnPurchasesUpdatedListener { result, purchases ->
                when (result.responseCode) {
                    BillingClient.BillingResponseCode.OK -> handlePurchases(purchases)
                    else -> listener.onPurchaseError(result.responseCode)
                }
            }
        }
    }

    private fun handlePurchases(purchase: Purchase) {
        if (purchase.isAcknowledged) {
            listener.onPurchaseSuccessful(purchase)
        } else {
            acknowledgePurchase(purchase)
        }
    }

    private fun acknowledgePurchase(purchase: Purchase) {
        val params = AcknowledgePurchaseParams.newBuilder()
            .setPurchaseToken(purchase.purchaseToken)
            .build()

        billingClient.acknowledgePurchase(params) { result ->
            if (result.responseCode == BillingClient.BillingResponseCode.OK) {
                listener.onPurchaseSuccessful(purchase)
            } else {
                listener.onAcknowledgmentFailed(result.responseCode)
            }
        }
    }

    fun secureHash(data: String): String {
        try {
            val digest = MessageDigest.getInstance("SHA-256")
            digest.update(data.toByteArray())
            return digest.digest().joinToString("") { "%02x".format(it) }
        } catch (e: NoSuchAlgorithmException) {
            e.printStackTrace()
            return ""
        }
    }

    interface PaymentListener {
        fun onBillingSetupFailed(responseCode: Int)
        fun onSkuDetailsLoaded(skuDetails: List<SkuDetails>)
        fun onQuerySkuDetailsFailed(responseCode: Int)
        fun onPurchaseError(responseCode: Int)
        fun onAcknowledgmentFailed(responseCode: Int)
        fun onPurchaseSuccessful(purchase: Purchase)
    }
}